"use client";

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import {
    CheckCircle2,
    ArrowRight,
    Sparkles,
    Heart,
    Smartphone,
    Activity,
    Instagram,
    User,
    Camera
} from 'lucide-react';

// Using the same theme-aware logic but enforcing light mode for onboarding warmth
const LIGHT_COLORS = {
    bg: "#f8f9ff",
    card: "#ffffff",
    text: "#111827",
    muted: "#6b7280",
    accent: "#6366f1",
    accentMuted: "rgba(99,102,241,0.1)",
    border: "rgba(0,0,0,0.06)",
};

export default function ClientSetupPage() {
    const { token } = useParams();
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [inviteData, setInviteData] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const [form, setForm] = useState({
        name: "",
        photoUrl: "",
    });
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        // Fetch invitation data
        const fetchInvite = async () => {
            try {
                const res = await fetch(`/api/invitations/${token}`);
                if (res.ok) {
                    const data = await res.json();
                    setInviteData(data);
                    setForm({ name: data.name, photoUrl: "" });
                } else {
                    setError("This invitation link is invalid or has expired.");
                }
            } catch (err) {
                setError("Something went wrong. Please try again later.");
            } finally {
                setLoading(false);
            }
        };
        if (token) fetchInvite();
    }, [token]);

    const handleTerraConnect = async () => {
        try {
            const res = await fetch("/api/terra/session", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ referenceId: token }),
            });
            const { url } = await res.json();
            if (url) window.location.href = url;
        } catch (err) {
            console.error("Terra connection failed", err);
        }
    };

    const handleComplete = async () => {
        setSubmitting(true);
        try {
            const res = await fetch(`/api/invitations/${token}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: form.name,
                    photoUrl: form.photoUrl,
                    // Integration IDs would be updated via webhooks or OAuth callbacks
                }),
            });
            if (res.ok) {
                router.push('/dashboard');
            } else {
                console.error("Failed to complete onboarding");
            }
        } catch (err) {
            console.error(err);
        } finally {
            setSubmitting(false);
        }
    };

    const handleNext = () => setStep(s => s + 1);

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin" />
        </div>
    );

    if (error) return (
        <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50 text-center">
            <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mb-4">
                <Smartphone className="text-red-500" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 mb-2">Oops!</h1>
            <p className="text-gray-500 max-w-xs">{error}</p>
        </div>
    );

    return (
        <div className="min-h-screen flex flex-col items-center p-6 sm:p-12 transition-all duration-500"
            style={{ backgroundColor: LIGHT_COLORS.bg }}>

            {/* Progress bar */}
            <div className="w-full max-w-lg h-1.5 bg-gray-200 rounded-full mb-12 overflow-hidden">
                <div className="h-full bg-indigo-500 transition-all duration-700 ease-out"
                    style={{ width: `${(step / 3) * 100}%` }} />
            </div>

            <main className="w-full max-w-lg">
                {step === 1 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
                        <div className="text-center">
                            <div className="inline-flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-xs font-bold mb-6">
                                <Sparkles size={12} />
                                Welcome to Kinetiq
                            </div>
                            <h1 className="text-4xl font-extrabold tracking-tight text-gray-900 leading-tight">
                                Your coach is ready <br />to support you.
                            </h1>
                            <p className="mt-4 text-gray-500 text-lg">
                                <strong>{inviteData?.coachName}</strong> invited you to track your progress and hit your goals together.
                            </p>
                        </div>

                        <div className="bg-white p-8 rounded-[32px] border border-gray-100 shadow-xl shadow-indigo-500/5">
                            <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-gray-100">
                                <div className="w-12 h-12 rounded-xl bg-indigo-500 flex items-center justify-center text-white font-bold text-xl overflow-hidden">
                                    {inviteData?.coachAvatar ? (
                                        <img src={inviteData.coachAvatar} alt={inviteData.coachName} className="w-full h-full object-cover" />
                                    ) : (
                                        inviteData?.coachName?.[0]
                                    )}
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-gray-900">{inviteData?.coachName}</p>
                                    <p className="text-xs text-gray-500 uppercase tracking-widest font-black">Certified Coach</p>
                                </div>
                            </div>
                        </div>

                        <button onClick={handleNext}
                            className="w-full py-5 rounded-[24px] bg-indigo-600 text-white font-black text-lg shadow-xl shadow-indigo-600/20 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3">
                            Get Started
                            <ArrowRight size={20} />
                        </button>
                    </div>
                )}

                {step === 2 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                        <div className="text-center">
                            <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Let's set up your profile</h2>
                            <p className="mt-2 text-gray-500">Confirm your details for the dashboard.</p>
                        </div>

                        <div className="space-y-6">
                            <div className="flex flex-col items-center gap-6">
                                <div className="relative group cursor-pointer">
                                    <div className="w-24 h-24 rounded-[28px] bg-white border border-gray-100 shadow-inner flex items-center justify-center overflow-hidden">
                                        {form.photoUrl ? (
                                            <img src={form.photoUrl} alt="Avatar Preview" className="w-full h-full object-cover" />
                                        ) : (
                                            <User className="text-gray-200" size={40} />
                                        )}
                                    </div>
                                    <button className="absolute -bottom-2 -right-2 w-10 h-10 bg-indigo-600 text-white rounded-2xl shadow-lg flex items-center justify-center hover:scale-110 active:scale-90 transition-all border-4 border-white">
                                        <Camera size={18} />
                                    </button>
                                </div>
                                <div className="w-full space-y-2">
                                    <label className="text-[12px] font-black uppercase tracking-widest text-gray-400 ml-1">Preferred Name</label>
                                    <input type="text" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })}
                                        className="w-full py-4 px-6 bg-white border border-gray-100 rounded-2xl outline-none focus:border-indigo-500 shadow-sm focus:shadow-indigo-500/10 transition-all font-bold text-gray-900"
                                        placeholder="Full Name" />
                                </div>
                            </div>
                        </div>

                        <button onClick={handleNext}
                            className="w-full py-5 rounded-[24px] bg-indigo-600 text-white font-black text-lg shadow-xl shadow-indigo-600/20 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3">
                            Next Step
                            <ArrowRight size={20} />
                        </button>
                    </div>
                )}

                {step === 3 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
                        <div className="text-center">
                            <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Connect your data</h2>
                            <p className="mt-2 text-gray-500">Link your devices so your coach can see your hard work.</p>
                        </div>

                        <div className="grid grid-cols-1 gap-4">
                            <button onClick={handleTerraConnect} className="group relative flex items-center gap-4 p-6 bg-white border border-gray-100 rounded-[32px] hover:border-indigo-500 transition-all text-left shadow-sm hover:shadow-lg hover:shadow-indigo-500/5">
                                <div className="w-14 h-14 rounded-2xl bg-rose-50 flex items-center justify-center shrink-0 border border-rose-100">
                                    <Heart className="text-rose-500" fill="currentColor" size={24} />
                                </div>
                                <div className="flex-1">
                                    <p className="font-black text-gray-900">Apple Health</p>
                                    <p className="text-xs text-gray-500 font-medium">Steps, Heart Rate, Activity</p>
                                </div>
                                <div className="w-8 h-8 rounded-full border border-gray-100 flex items-center justify-center group-hover:bg-indigo-600 group-hover:border-indigo-600 transition-all">
                                    <ArrowRight size={14} className="text-gray-300 group-hover:text-white" />
                                </div>
                            </button>

                            <button className="group relative flex items-center gap-4 p-6 bg-white border border-gray-100 rounded-[32px] hover:border-orange-500 transition-all text-left shadow-sm hover:shadow-lg hover:shadow-orange-500/5">
                                <div className="w-14 h-14 rounded-2xl bg-orange-50 flex items-center justify-center shrink-0 border border-orange-100">
                                    <Activity className="text-orange-600" size={24} />
                                </div>
                                <div className="flex-1">
                                    <p className="font-black text-gray-900">Strava</p>
                                    <p className="text-xs text-gray-500 font-medium">Runs, Cycling, Workouts</p>
                                </div>
                                <div className="w-8 h-8 rounded-full border border-gray-100 flex items-center justify-center group-hover:bg-orange-500 group-hover:border-orange-500 transition-all">
                                    <ArrowRight size={14} className="text-gray-300 group-hover:text-white" />
                                </div>
                            </button>
                        </div>

                        <div className="pt-4 space-y-4">
                            <button onClick={handleComplete} disabled={submitting}
                                className="w-full py-5 rounded-[24px] bg-gray-900 text-white font-black text-lg shadow-xl shadow-gray-900/10 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-3 disabled:opacity-50">
                                {submitting ? "Finishing up..." : "Complete Setup"}
                                <CheckCircle2 size={20} />
                            </button>
                            <p className="text-center text-[12px] text-gray-400 font-bold uppercase tracking-widest px-8">
                                By completing setup, you agree to share your health signals with your coach.
                            </p>
                        </div>
                    </div>
                )}
            </main>

            <footer className="mt-12 text-center">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Powered by Kinetiq AI</p>
            </footer>

            <style jsx global>{`
                @keyframes fadeIn {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
                .animate-in {
                    animation: fadeIn 0.5s ease-out forwards;
                }
            `}</style>
        </div>
    );
}
